def _sigmoid(x):
    if x >= 0.0:
        z = math.exp(-x)
        return 1.0 / (1.0 + z)
    z = math.exp(x)
    return z / (1.0 + z)

def _silu(x):
    return x * _sigmoid(x)

def _linear(vec, weight, bias):
    out = []
    for row, b in zip(weight, bias):
        out.append(b + sum(v * w for v, w in zip(vec, row)))
    return out

def _layer_norm(vec, weight, bias):
    n = max(1, len(vec))
    mean = sum(vec) / n
    var = sum((v - mean) * (v - mean) for v in vec) / n
    inv = 1.0 / math.sqrt(var + 1.0e-5)
    return [(v - mean) * inv * w + b for v, w, b in zip(vec, weight, bias)]

def _softmax(vals):
    if not vals:
        return []
    m = max(vals)
    exps = [math.exp(v - m) for v in vals]
    denom = sum(exps) or 1.0
    return [v / denom for v in exps]

def _mha(tokens, block):
    n = len(tokens)
    if n == 0:
        return []
    d_model = MODEL['d_model']
    heads = MODEL['heads']
    head_dim = d_model // heads
    scale = 1.0 / math.sqrt(float(head_dim))
    qs, ks, vs = [], [], []
    for tok in tokens:
        qkv = _linear(tok, block['attn_in_w'], block['attn_in_b'])
        qs.append(qkv[:d_model])
        ks.append(qkv[d_model:2*d_model])
        vs.append(qkv[2*d_model:])
    outs = []
    for i in range(n):
        merged = []
        for h in range(heads):
            off = h * head_dim
            qh = qs[i][off:off + head_dim]
            scores = []
            for j in range(n):
                kh = ks[j][off:off + head_dim]
                scores.append(sum(a * b for a, b in zip(qh, kh)) * scale)
            probs = _softmax(scores)
            head = []
            for k in range(head_dim):
                head.append(sum(probs[j] * vs[j][off + k] for j in range(n)))
            merged.extend(head)
        outs.append(_linear(merged, block['attn_out_w'], block['attn_out_b']))
    return outs

def _block(tokens, block):
    z = [_layer_norm(tok, block['norm1_w'], block['norm1_b']) for tok in tokens]
    attn = _mha(z, block)
    x = [[a + b for a, b in zip(tok, add)] for tok, add in zip(tokens, attn)]
    z2 = [_layer_norm(tok, block['norm2_w'], block['norm2_b']) for tok in x]
    ff = []
    for tok in z2:
        hid = [_silu(v) for v in _linear(tok, block['ff1_w'], block['ff1_b'])]
        ff.append(_linear(hid, block['ff2_w'], block['ff2_b']))
    return [[a + b for a, b in zip(tok, add)] for tok, add in zip(x, ff)]

def _embed(row, idx):
    vec = [(float(v) - m) / s for v, m, s in zip(row, MEAN, STD)]
    h = [_silu(v) for v in _linear(vec, WEIGHTS['input_w'], WEIGHTS['input_b'])]
    pos = WEIGHTS['rank_embedding'][idx if idx < len(WEIGHTS['rank_embedding']) else -1]
    return [a + b for a, b in zip(h, pos)]

def score_many(rows):
    if not rows:
        return []
    tokens = [_embed(row, idx) for idx, row in enumerate(rows)]
    for block in WEIGHTS['blocks']:
        tokens = _block(tokens, block)
    tokens = [_layer_norm(tok, WEIGHTS['norm_w'], WEIGHTS['norm_b']) for tok in tokens]
    width = len(tokens[0]) if tokens else 0
    inv_n = 1.0 / max(1, len(tokens))
    ctx = [sum(tok[i] for tok in tokens) * inv_n for i in range(width)]
    scores = []
    for h in tokens:
        z = h + ctx + [a * b for a, b in zip(h, ctx)]
        hidden = [_silu(v) for v in _linear(z, WEIGHTS['score1_w'], WEIGHTS['score1_b'])]
        scores.append(_linear(hidden, WEIGHTS['score2_w'], WEIGHTS['score2_b'])[0])
    return scores

def score(row):
    vals = score_many([row])
    return vals[0] if vals else 0.0
